#include <stdio.h>

struct Process {
    int pid;
    int arrival_time;
    int burst_time;
    int completion_time;
    int turnaround_time;
    int waiting_time;
    int response_time;
};

void calculateMetrics(struct Process proc[], int n) {
    int current_time = 0;
    int total_waiting = 0, total_turnaround = 0, total_response = 0;

    // FCFS: processes sorted by arrival time assumed
    for (int i = 0; i < n; i++) {
        if (current_time < proc[i].arrival_time)
            current_time = proc[i].arrival_time;

        // Response time: first CPU access - arrival
        proc[i].response_time = current_time - proc[i].arrival_time;

        // Waiting time: turnaround - burst time
        current_time += proc[i].burst_time;
        proc[i].completion_time = current_time;
        proc[i].turnaround_time = proc[i].completion_time - proc[i].arrival_time;
        proc[i].waiting_time = proc[i].turnaround_time - proc[i].burst_time;

        total_waiting += proc[i].waiting_time;
        total_turnaround += proc[i].turnaround_time;
        total_response += proc[i].response_time;
    }

    printf("Average Waiting Time: %.2f\n", (float)total_waiting/n);
    printf("Average Turnaround Time: %.2f\n", (float)total_turnaround/n);
    printf("Average Response Time: %.2f\n", (float)total_response/n);
}

int main() {
    struct Process proc[] = {{1, 0, 10}, {2, 1, 5}, {3, 2, 8}};
    int n = sizeof(proc)/sizeof(proc[0]);
    calculateMetrics(proc, n);
    return 0;
}
